#include <zephyr/init.h>
#include <zephyr/drivers/i2c.h>
#include <zephyr/logging/log.h>

LOG_MODULE_REGISTER(awohali_h745_board, LOG_LEVEL_INF);

/* USB2422 register addresses */
#define USB2422_ADDR        0x2C
#define USB2422_REG_VID_L   0x00
#define USB2422_REG_CONFIG  0x06
#define USB2422_STCD        0xFF  /* Status/Command register - write 0x01 to attach */

static const struct device *i2c_dev = DEVICE_DT_GET(DT_NODELABEL(i2c1));

static int usb2422_init(void)
{
    if (!device_is_ready(i2c_dev)) {
        LOG_ERR("I2C device not ready");
        return -ENODEV;
    }

    /*
     * USB2422 SMBus configuration block write.
     * Writes config registers starting at offset 0x00.
     * Consult USB2422 datasheet section 3.0 for full register map.
     */
    uint8_t config[] = {
        USB2422_REG_VID_L,  /* starting register */
        0x24, 0x04,         /* VID = 0x0424 (Microchip) */
        0x22, 0x24,         /* PID = 0x2422 */
        0x00, 0x01,         /* DID = 0x0100*/
        0xB8,               /* CFG1: self-powered, ganged port switching */
        0x28,               /* CFG2 */
        0x01,               /* CFG3 */
        0x06,               /* NRD: both ports are non-removable */
        0x00,               /* PDS */
        0x00,               /* PDB */
        0x01,               /* MAXPS: self-powered - 2mA */
        0x32,               /* MAXPB: bus-powered - 100mA */
        0x01,               /* HCMCS: self-powered - 2mA */
        0x32,               /* HCMCB: bus-powered - 100mA */
        0x32,               /* PWRT: power-on time - 100ms */
        0x09, 0x04,         /* LANGID = 0x0409 */
        0x15,               /* MFRSL: manufacturer string length - 21 */
        0x07,               /* PRDSL: product string length - 7 */
        0x04,               /* SERSL: serial string length - 4 */
        0x44, 0x00, 0x65, 0x00, 0x65, 0x00, 0x70, 0x00, /* Manufacturer Name */
        0x53, 0x00, 0x70, 0x00, 0x61, 0x00, 0x63, 0x00,
        0x65, 0x00, 0x20, 0x00, 0x45, 0x00, 0x6E, 0x00,
        0x67, 0x00, 0x69, 0x00, 0x6E, 0x00, 0x65, 0x00,
        0x65, 0x00, 0x72, 0x00, 0x69, 0x00, 0x6E, 0x00,
        0x67, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x41, 0x00, 0x77, 0x00, 0x6F, 0x00, 0x68, 0x00, /* Product Name */
        0x61, 0x00, 0x6C, 0x00, 0x69, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x31, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, /* Serial */
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00,               /* BC_EN */
        0x00,               /* BOOSTUP */
        0x00,               /* BOOST40 */
        0x00,               /* PRTSP */
        0x21                /* PRTR12: physical and logical ports match*/
    };

    int ret = i2c_write(i2c_dev, config, sizeof(config), USB2422_ADDR);
    if (ret < 0) {
        LOG_ERR("Failed to configure USB2422: %d", ret);
        return ret;
    }

    /* Write 0x01 to STCD register (0xFF) to attach the hub */
    uint8_t attach[] = {USB2422_STCD, 0x01};
    ret = i2c_write(i2c_dev, attach, sizeof(attach), USB2422_ADDR);
    if (ret < 0) {
        LOG_ERR("Failed to attach USB2422: %d", ret);
        return ret;
    }

    LOG_INF("USB2422 initialized");
    return 0;
}

/* Must be POST_KERNEL so I2C driver is already up */
SYS_INIT(usb2422_init, POST_KERNEL, CONFIG_KERNEL_INIT_PRIORITY_DEVICE);